INSERT INTO `v1_acaf60d7cd740103cdef894c86792ba07911d46edf3a15d3fb9a706b278a8afd` VALUES ("", 10, 11, 1030021, 1, "そういうことか\nいや、ちょっとまって、しまむー\nプチグリフォンはかわいいかもだけど\nぴにゃこら太、かわいいかな～？", "", 3, 1, "", 112611);
INSERT INTO `v1_acaf60d7cd740103cdef894c86792ba07911d46edf3a15d3fb9a706b278a8afd` VALUES ("", "", 93, 1030022, "", 1, "", 3, "", "", 1.5);
