INSERT INTO `v1_acaf60d7cd740103cdef894c86792ba07911d46edf3a15d3fb9a706b278a8afd` VALUES ("", 10, 11, 1030028, 1, "かわいいですよ～\n私たちの歌で、たくさんの\nぴにゃこら太さんを\n集められませんかね？", "", 3, 1, "", 112411);
