INSERT INTO `v1_acaf60d7cd740103cdef894c86792ba07911d46edf3a15d3fb9a706b278a8afd` VALUES ("", 10, 11, 1070031, 1, "まーたしかに、あのときの\nウヅキたちのゲリラLIVEは\nほんとにボロボロだったわね！", "", 7, 1, "", 106031);
