INSERT INTO `v1_acaf60d7cd740103cdef894c86792ba07911d46edf3a15d3fb9a706b278a8afd` VALUES ("", 10, 11, 1070036, 1, "もうっ、キャルキャル～\nあんま言わないでよ～！\n私たちだってわかってるんだからさ～", "", 7, 1, "", 112611);
